input.command:
node -e "
const m = require('./.gsd-t/ratelimit-map.json');
const safe = m.matrix.filter(c => c.summary && c.summary.declaredSafe);
const peakWorkers = safe.reduce((mx,c) => Math.max(mx, c.workers), 0);
const total429 = m.matrix.reduce((s,c) => s + (c.summary?.total429 || 0), 0);
const cellsRun = m.matrix.length;
const recRaw = m.recommended || {};
console.log(JSON.stringify({
  cellsRun,
  safeCellCount: safe.length,
  peakSafeWorkers: peakWorkers,
  total429: total429,
  recommended: recRaw,
  steadyStateOk: m.steadyState && m.steadyState.ok,
  backoffMs: m.backoffProbe && (m.backoffProbe.first200OkAtMs ?? null)
}, null, 2));
"
